465			json density_network_hyperparams = m_density_network->hyperparams();
466			density_network_hyperparams["n_output_dims"] = m_density_network->padded_output_width();
467			return {
468				{"otype", "NerfNetwork"},
469				{"pos_encoding", m_pos_encoding->hyperparams()},
470				{"dir_encoding", m_dir_encoding->hyperparams()},
471				{"density_network", density_network_hyperparams},
472				{"rgb_network", m_rgb_network->hyperparams()},
473			};
474		}
